module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

    reg [3:0] i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) i <= 4'd0;
        else if (start && i < 4'd17) i <= i + 1;
        else if (!start) i <= 4'd0;
    end
    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) done_r <= 1'b0;
        else if (i == 4'd16) done_r <= 1'b1;
        else if (i == 4'd17) done_r <= 1'b0;
    end
    assign done = done_r;
    reg [31:0] yout_r;
    reg [15:0] areg;
    reg [15:0] breg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg   <= 16'b0;
            breg   <= 16'b0;
            yout_r <= 32'b0;
        end else if (start) begin
            if (i == 4'd0) begin
                areg <= ain;
                breg <= bin;
            end else if (i > 4'd0 && i < 4'd17) begin
                if (areg[i-1'b1]) yout_r <= (yout_r + (breg << (i-1))) ;
            end
        end
    end
    assign yout = yout_r;
endmodule
